mapper.select:
select c.*, d.name as department_name, u.real_name as teacher_name from activity_info c left join campus_info d on c.department_id = d.id left join sys_user u on c.teacher_id = u.id
and c.course_name like concat('%', #{courseName}, '%')
and c.teacher_id = #{teacherId}
and c.status = #{status}
order by c.id desc

mapper.update:
update activity_info
course_name = #{courseName}, course_code = #{courseCode}, department_id = #{departmentId}, teacher_id = #{teacherId}, credit = #{credit}, course_type = #{courseType}, course_hours = #{courseHours}, course_desc = #{courseDesc}, status = #{status},
where id = #{id}
